// pages/Quiz.jsx — Professional Quiz Experience
// Features: topic selector, animated MCQ cards, live timer, progress bar,
//           animated score reveal, per-question explanations, confetti on high score.
// FIX: saves quiz scores to localStorage via saveQuizScore() on completion.

import React, { useState, useEffect, useRef, useCallback } from "react";
import { Link } from "react-router-dom";
import { saveQuizScore } from "../utils/progress"; // ← FIX: import added

const API_BASE = process.env.REACT_APP_API_URL || "http://localhost:5000";

// ─── Constants ───────────────────────────────────────────────────────────────
const TOPICS = [
  "Percentages", "Profit & Loss", "Simple Interest", "Compound Interest",
  "Time & Work", "Time & Distance", "Ratio & Proportion", "Averages",
  "Mixtures & Alligation", "Number System", "HCF & LCM", "Pipes & Cisterns",
  "Permutation & Combination", "Probability","Algebra","Geometry","Areas", "Boats & Streams",
];

const DIFFICULTY_LABELS = { 5: "Quick", 10: "Standard", 15: "Deep Dive" };
const TIME_PER_Q = 45; // seconds

// ─── Utility ─────────────────────────────────────────────────────────────────
function fmt(s) {
  const m = Math.floor(s / 60), sec = s % 60;
  return `${m}:${sec.toString().padStart(2, "0")}`;
}

function scoreGrade(pct) {
  if (pct >= 90) return { label: "Excellent!", color: "#22c55e", emoji: "🏆" };
  if (pct >= 70) return { label: "Great Job!", color: "#38bdf8", emoji: "🎯" };
  if (pct >= 50) return { label: "Good Effort", color: "#f59e0b", emoji: "👍" };
  return { label: "Keep Practicing", color: "#f87171", emoji: "📚" };
}

// ─── Confetti ─────────────────────────────────────────────────────────────────
function Confetti() {
  const canvasRef = useRef(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    const particles = Array.from({ length: 120 }, () => ({
      x: Math.random() * canvas.width,
      y: -20,
      vx: (Math.random() - 0.5) * 3,
      vy: 2 + Math.random() * 3,
      color: ["#6366f1","#38bdf8","#22c55e","#f59e0b","#f472b6","#a78bfa"][Math.floor(Math.random()*6)],
      size: 6 + Math.random() * 8,
      rot: Math.random() * 360,
      rotV: (Math.random() - 0.5) * 5,
    }));
    let frame;
    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      particles.forEach(p => {
        p.x += p.vx; p.y += p.vy; p.rot += p.rotV;
        if (p.y > canvas.height) { p.y = -20; p.x = Math.random() * canvas.width; }
        ctx.save();
        ctx.translate(p.x, p.y);
        ctx.rotate(p.rot * Math.PI / 180);
        ctx.fillStyle = p.color;
        ctx.fillRect(-p.size/2, -p.size/2, p.size, p.size);
        ctx.restore();
      });
      frame = requestAnimationFrame(draw);
    };
    draw();
    return () => cancelAnimationFrame(frame);
  }, []);
  return (
    <canvas
      ref={canvasRef}
      style={{ position:"fixed", inset:0, pointerEvents:"none", zIndex:100, opacity:0.7 }}
    />
  );
}

