// ─── Question Card ─────────────────────────────────────────────────────────────
function QuestionCard({ q, index, total, timeLeft, onAnswer, answered, selected }) {
  const pct = (timeLeft / TIME_PER_Q) * 100;
  const timerColor = timeLeft > 15 ? "#22c55e" : timeLeft > 7 ? "#f59e0b" : "#ef4444";
  const opts = ["A","B","C","D"];

  return (
    <div style={{ maxWidth:640, margin:"0 auto", padding:"20px", animation:"slideIn 0.35s ease both" }}>
      {/* Top bar */}
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:20 }}>
        <span style={{ fontSize:"0.75rem", color:"#64748b", fontWeight:600 }}>
          Question <span style={{ color:"#a5b4fc" }}>{index+1}</span> / {total}
        </span>
        <div style={{ display:"flex", alignItems:"center", gap:8 }}>
          <div style={{
            width:36, height:36, borderRadius:10,
            border:`2px solid ${timerColor}`,
            display:"flex", alignItems:"center", justifyContent:"center",
            fontSize:"0.72rem", fontWeight:700, color:timerColor,
            background:`${timerColor}15`,
            transition:"all 0.5s",
            animation: timeLeft <= 7 ? "pulse 0.8s ease-in-out infinite" : "none"
          }}>
            {timeLeft}s
          </div>
        </div>
      </div>

      {/* Progress */}
      <div style={{ height:3, background:"rgba(255,255,255,0.05)", borderRadius:4, marginBottom:24 }}>
        <div style={{
          height:"100%", borderRadius:4, transition:"width 1s linear",
          width:`${pct}%`,
          background:`linear-gradient(90deg, ${timerColor}, ${timerColor}aa)`
        }} />
      </div>

      {/* Question */}
      <div style={{
        padding:"20px 22px", borderRadius:16, marginBottom:20,
        background:"rgba(255,255,255,0.03)", border:"1px solid rgba(255,255,255,0.07)",
      }}>
        <p style={{ margin:0, color:"#e2e8f0", fontSize:"0.95rem", lineHeight:1.65, fontWeight:500 }}>
          {q.question}
        </p>
      </div>

      {/* Options */}
      <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
        {q.options.map((opt, i) => {
          const letter = opts[i];
          const isSelected = selected === letter;
          const isCorrect = answered && letter === q.answer;
          const isWrong = answered && isSelected && letter !== q.answer;

          let bg = "rgba(255,255,255,0.03)";
          let border = "rgba(255,255,255,0.07)";
          let color = "#94a3b8";
          let pillBg = "rgba(255,255,255,0.05)";
          let pillColor = "#475569";

          if (isCorrect) {
            bg = "rgba(34,197,94,0.1)"; border = "rgba(34,197,94,0.35)";
            color = "#86efac"; pillBg = "rgba(34,197,94,0.2)"; pillColor = "#22c55e";
          } else if (isWrong) {
            bg = "rgba(239,68,68,0.1)"; border = "rgba(239,68,68,0.35)";
            color = "#fca5a5"; pillBg = "rgba(239,68,68,0.2)"; pillColor = "#ef4444";
          } else if (isSelected && !answered) {
            bg = "rgba(99,102,241,0.1)"; border = "rgba(99,102,241,0.4)";
            color = "#c7d2fe"; pillBg = "rgba(99,102,241,0.2)"; pillColor = "#818cf8";
          }

          return (
            <button
              key={letter}
              disabled={answered}
              onClick={() => onAnswer(letter)}
              style={{
                display:"flex", alignItems:"center", gap:14, padding:"13px 16px",
                borderRadius:12, border:`1px solid ${border}`, background:bg,
                cursor: answered ? "default" : "pointer", textAlign:"left",
                transition:"all 0.2s", color,
                transform: isSelected && !answered ? "scale(1.005)" : "scale(1)",
              }}
            >
              <span style={{
                shrink:0, width:28, height:28, borderRadius:8,
                display:"flex", alignItems:"center", justifyContent:"center",
                fontSize:"0.72rem", fontWeight:700,
                background:pillBg, color:pillColor,
                flexShrink:0,
              }}>
                {letter}
              </span>
              <span style={{ fontSize:"0.87rem", lineHeight:1.5 }}>{opt}</span>
              {isCorrect && <span style={{ marginLeft:"auto", fontSize:"1rem" }}>✓</span>}
              {isWrong   && <span style={{ marginLeft:"auto", fontSize:"1rem" }}>✗</span>}
            </button>
          );
        })}
      </div>

      {/* Explanation */}
      {answered && q.explanation && (
        <div style={{
          marginTop:16, padding:"14px 16px", borderRadius:12,
          background:"rgba(56,189,248,0.07)", border:"1px solid rgba(56,189,248,0.18)",
          animation:"fadeUp 0.3s ease both"
        }}>
          <p style={{ margin:0, fontSize:"0.75rem", color:"#7dd3fc", fontWeight:600, marginBottom:4 }}>
            💡 Explanation
          </p>
          <p style={{ margin:0, fontSize:"0.82rem", color:"#bae6fd", lineHeight:1.6 }}>
            {q.explanation}
          </p>
        </div>
      )}
    </div>
  );
}

// ─── Result Screen ─────────────────────────────────────────────────────────────
