  const pct = Math.round((correct / questions.length) * 100);
  const grade = scoreGrade(pct);
  const showConfetti = pct >= 70;

  const [visible, setVisible] = useState(false);
  useEffect(() => { setTimeout(() => setVisible(true), 100); }, []);

  return (
    <div style={{ maxWidth:580, margin:"0 auto", padding:"40px 20px" }}>
      {showConfetti && <Confetti />}

      {/* Score card */}
      <div style={{
        textAlign:"center", padding:"36px 24px", borderRadius:20, marginBottom:24,
        background:"rgba(255,255,255,0.02)", border:"1px solid rgba(255,255,255,0.07)",
        animation:"fadeUp 0.5s ease both",
        position:"relative", overflow:"hidden"
      }}>
        <div style={{
          position:"absolute", inset:0,
          background:`radial-gradient(circle at 50% 0%, ${grade.color}15 0%, transparent 65%)`,
          pointerEvents:"none"
        }} />

        <div style={{ fontSize:"2.5rem", marginBottom:12 }}>{grade.emoji}</div>
        <h2 style={{ margin:"0 0 4px", fontSize:"1.4rem", fontWeight:800, color:"#f8fafc" }}>
          {grade.label}
        </h2>
        <p style={{ margin:"0 0 24px", fontSize:"0.8rem", color:"#64748b" }}>{topic}</p>

        {/* Big score */}
        <div style={{
          display:"inline-flex", alignItems:"baseline", gap:4, marginBottom:20
        }}>
          <span style={{
            fontSize: visible ? "3.5rem" : "0",
            fontWeight:800, color:grade.color,
            transition:"font-size 0.8s cubic-bezier(0.34,1.56,0.64,1)",
            lineHeight:1,
          }}>
            {pct}
          </span>
          <span style={{ fontSize:"1.2rem", color:"#475569", fontWeight:600 }}>%</span>
        </div>

        {/* Score detail */}
        <div style={{ display:"flex", justifyContent:"center", gap:32 }}>
          {[
            { lbl:"Correct", val:correct, color:"#22c55e" },
            { lbl:"Wrong", val:questions.length - correct, color:"#f87171" },
            { lbl:"Total", val:questions.length, color:"#94a3b8" },
