// ─── Main Quiz Component ──────────────────────────────────────────────────────
export default function Quiz() {
  const [phase, setPhase] = useState("setup"); // setup | loading | quiz | result
  const [questions, setQuestions] = useState([]);
  const [qIndex, setQIndex] = useState(0);
  const [answers, setAnswers] = useState([]);
  const [selected, setSelected] = useState(null);
  const [answered, setAnswered] = useState(false);
  const [timeLeft, setTimeLeft] = useState(TIME_PER_Q);
  const [error, setError] = useState("");
  const [quizTopic, setQuizTopic] = useState("");
  const [quizCount, setQuizCount] = useState(10);

  const timerRef = useRef(null);

  const clearTimer = () => clearInterval(timerRef.current);

  const advanceQuestion = useCallback((chosenAnswer) => {
    clearTimer();
    setAnswers(prev => {
      const next = [...prev, chosenAnswer]; // accumulate answers

      const nextIdx = qIndex + 1;
      if (nextIdx >= questions.length) {
        // ── FIX: save score to localStorage when quiz completes ──
        const correctCount = questions.filter((q, i) => next[i] === q.answer).length;
        saveQuizScore(quizTopic, correctCount, questions.length);
      }

      return next;
    });
    setAnswered(true);
    setTimeout(() => {
      setQIndex(prev => {
        const nextIdx = prev + 1;
        if (nextIdx >= questions.length) {
          setPhase("result");
        } else {
          setSelected(null);
          setAnswered(false);
          setTimeLeft(TIME_PER_Q);
        }
        return nextIdx;
      });
    }, 1400);
  }, [qIndex, questions, quizTopic]);

  // Timer
  useEffect(() => {
    if (phase !== "quiz" || answered) return;
    timerRef.current = setInterval(() => {
      setTimeLeft(t => {
        if (t <= 1) { advanceQuestion(null); return TIME_PER_Q; }
        return t - 1;
      });
    }, 1000);
    return clearTimer;
  }, [phase, answered, qIndex, advanceQuestion]);

  const startQuiz = async (topic, count) => {
    setQuizTopic(topic);
    setQuizCount(count);
    setPhase("loading");
    setError("");
    setAnswers([]); // ← FIX: reset answers array on new quiz start
    try {
      const res = await fetch(`${API_BASE}/api/quiz`, {
        method:"POST",
        headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ topic, count }),
      });
      const json = await res.json();
      if (!res.ok || !json.success) throw new Error(json.details || json.error || "Server error");
      setQuestions(json.questions);
      setQIndex(0);
      setSelected(null);
      setAnswered(false);
      setTimeLeft(TIME_PER_Q);
      setPhase("quiz");
    } catch (err) {
      setError(err.message);
      setPhase("error");
    }
  };

  const handleAnswer = (letter) => {
    if (answered) return;
    setSelected(letter);
    advanceQuestion(letter);
  };

  // Global keypress A/B/C/D
  useEffect(() => {
    if (phase !== "quiz" || answered) return;
    const handler = (e) => {
      const k = e.key.toUpperCase();
      if (["A","B","C","D"].includes(k)) handleAnswer(k);
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [phase, answered, handleAnswer]);

  return (
    <>
      <style>{`
        @keyframes fadeUp { from { opacity:0; transform:translateY(14px); } to { opacity:1; transform:translateY(0); } }
        @keyframes slideIn { from { opacity:0; transform:translateX(20px); } to { opacity:1; transform:translateX(0); } }
        @keyframes pulse { 0%,100% { transform:scale(1); } 50% { transform:scale(1.06); } }
      `}</style>

      {phase === "setup"   && <SetupScreen onStart={startQuiz} />}
      {phase === "loading" && <LoadingScreen topic={quizTopic} />}
      {phase === "error"   && <ErrorPanel msg={error} onBack={() => setPhase("setup")} />}

      {phase === "quiz" && questions[qIndex] && (
        <QuestionCard
          key={qIndex}
          q={questions[qIndex]}
          index={qIndex}
          total={questions.length}
          timeLeft={timeLeft}
          onAnswer={handleAnswer}
          answered={answered}
          selected={selected}
        />
      )}

      {phase === "result" && (
        <ResultScreen
          questions={questions}
          answers={answers}
          topic={quizTopic}
          onRetry={() => startQuiz(quizTopic, quizCount)}
          onNew={() => setPhase("setup")}
        />
      )}
    </>
  );
}
